// Helpers para config dinámica de clases
const DEFAULT_CLASES_CONFIG = CLASES_LIST.map(k=>({key:k,nombre:k,color:CLASE_COLORS[k]}));
function getCfgList(clasesConfig){return clasesConfig&&clasesConfig.length?clasesConfig:DEFAULT_CLASES_CONFIG;}
function getCfgColor(key,clasesConfig){return getCfgList(clasesConfig).find(c=>c.key===key)?.color||CLASE_COLORS[key]||"#5B2D8E";}
function getCfgKeys(clasesConfig){return getCfgList(clasesConfig).map(c=>c.key);}
// Deriva el objeto clases { CORDERITOS: [...], VENCEDORES: [...], ... } desde la lista de alumnos (fuente de verdad).
function deriveClases(alumnos,clasesConfig){
  const keys=getCfgKeys(clasesConfig);
  const out={};
  keys.forEach(k=>{ out[k]=[]; });
  (alumnos||[]).forEach(a=>{
    const key=normalizarClase(a.clase);
    if(!out[key])out[key]=[];
    let edad=null,cumpleanos=null;
    if(a.nacimiento){
      try{
        const d=new Date(a.nacimiento);
        const hoy=new Date();
        edad=String(hoy.getFullYear()-d.getFullYear()-(hoy<new Date(hoy.getFullYear(),d.getMonth(),d.getDate())?1:0));
        cumpleanos=`${String(d.getDate()).padStart(2,"0")}/${String(d.getMonth()+1).padStart(2,"0")}`;
      }catch(e){}
    }
    out[key].push({ id: a.id, nombre: a.nombre, primerNombre: a.primerNombre, segundoNombre: a.segundoNombre, primerApellido: a.primerApellido, segundoApellido: a.segundoApellido, edad, foto: a.foto||null, nacimiento: a.nacimiento, cumpleanos, bautizado: !!a.bautizado, sellado: !!a.sellado, padre: a.padre||"", madre: a.madre||"", telPadre: a.telPadre||"", telMadre: a.telMadre||"" });
  });
  return out;
}
// Devuelve {nombre, clase} de quienes aparecen en calificaciones pero no en alumnos (evita pérdida de lista).
function getMissingAlumnosFromCalificaciones(calificaciones,alumnos){
  if(!calificaciones||!Array.isArray(calificaciones)||calificaciones.length===0)return [];
  const seen=new Set();
  const out=[];
  calificaciones.forEach(c=>{
    const nombre=(c.alumno||"").trim();
    const clase=normalizarClase(c.clase);
    if(!nombre)return;
    const key=nombre+"|"+clase;
    if(seen.has(key))return;
    seen.add(key);
    const yaEsta=(alumnos||[]).some(a=>samePersonName(a.nombre,nombre)&&normalizarClase(a.clase)===clase);
    if(!yaEsta)out.push({nombre,clase});
  });
  return out;
}

// Devuelve {nombre, clase, foto} de quienes aparecen en el objeto clases guardado pero no en alumnos (foto por si el niño en clases la tiene).
function getMissingAlumnosFromClases(loadedClases,alumnos){
  if(!loadedClases||typeof loadedClases!=="object")return [];
  const out=[];
  const seen=new Set();
  Object.entries(loadedClases).forEach(([claseKey,arr])=>{
    if(!Array.isArray(arr))return;
    const clase=normalizarClase(claseKey);
    arr.forEach(n=>{
      const nombre=(n.nombre||"").trim();
      if(!nombre)return;
      const key=nombre+"|"+clase;
      if(seen.has(key))return;
      seen.add(key);
      const yaEsta=(alumnos||[]).some(a=>samePersonName(a.nombre,nombre)&&normalizarClase(a.clase)===clase);
      if(!yaEsta)out.push({nombre,clase,foto:n.foto||null});
    });
  });
  return out;
}

// Restaura foto en alumnos desde el objeto clases guardado (mismo nombre y clase). Modifica alumnos in-place y devuelve true si hubo cambios.
function restoreFotosFromClases(alumnos,loadedClases){
  if(!loadedClases||typeof loadedClases!=="object"||!alumnos||!alumnos.length)return false;
  const niñosConFoto=[]; // { nombre, clase, foto }
  Object.entries(loadedClases).forEach(([claseKey,arr])=>{
    if(!Array.isArray(arr))return;
    const clase=normalizarClase(claseKey);
    arr.forEach(n=>{
      const nombre=(n.nombre||"").trim();
      if(!nombre||!n.foto)return;
      niñosConFoto.push({nombre,clase,foto:n.foto});
    });
  });
  let changed=false;
  alumnos.forEach(a=>{
    if(a.foto)return;
    const claseA=normalizarClase(a.clase);
    const match=niñosConFoto.find(n=>samePersonName(n.nombre,a.nombre)&&normalizarClase(n.clase)===claseA);
    if(match){ a.foto=match.foto; changed=true; }
  });
  return changed;
}

// Restaura foto en alumnos desde la lista de familias guardada (cada f tiene alumno y foto). Modifica alumnos in-place y devuelve true si hubo cambios.
function restoreFotosFromFamilias(alumnos,loadedFamilias){
  if(!loadedFamilias||!Array.isArray(loadedFamilias)||!alumnos||!alumnos.length)return false;
  let changed=false;
  alumnos.forEach(a=>{
    if(a.foto)return;
    const fam=loadedFamilias.find(f=>samePersonName((f.alumno||"").trim(),a.nombre));
    if(fam&&fam.foto){ a.foto=fam.foto; changed=true; }
  });
  return changed;
}

// Restaura todos los datos de alumnos (bautizado, sellado, padres, teléfonos, nacimiento, familia, nombre desglosado) desde clases o familias guardados.
// Busca en todas las claves del objeto clases por si el formato de clave difiere; prioriza datos no vacíos del almacenamiento.
function restoreAlumnoDataFromStored(alumnos,loadedClases,loadedFamilias){
  if(!alumnos||!alumnos.length)return false;
  const storedByNombreClase=[]; // { nombre, clase, ...datos }
  if(loadedClases&&typeof loadedClases==="object"){
    Object.entries(loadedClases).forEach(([claseKey,arr])=>{
      if(!Array.isArray(arr))return;
      const clase=normalizarClase(claseKey);
      arr.forEach(n=>{
        const nombre=(n.nombre||"").trim();
        if(!nombre)return;
        storedByNombreClase.push({ nombre, clase, bautizado:n.bautizado, sellado:n.sellado, nacimiento:n.nacimiento, padre:n.padre, madre:n.madre, telPadre:n.telPadre, telMadre:n.telMadre, familia:n.familia, primerNombre:n.primerNombre, segundoNombre:n.segundoNombre, primerApellido:n.primerApellido, segundoApellido:n.segundoApellido, foto:n.foto });
      });
    });
  }
  if(loadedFamilias&&Array.isArray(loadedFamilias)){
    loadedFamilias.forEach(f=>{
      const nombre=(f.alumno||"").trim();
      if(!nombre)return;
      const clase=normalizarClase(f.clase);
      storedByNombreClase.push({ nombre, clase, bautizado:f.bautizado, sellado:f.sellado, nacimiento:f.nacimiento, padre:f.padre, madre:f.madre, telPadre:f.telPadre, telMadre:f.telMadre, familia:f.familia, primerNombre:f.primerNombre, segundoNombre:f.segundoNombre, primerApellido:f.primerApellido, segundoApellido:f.segundoApellido, foto:f.foto });
    });
  }
  let changed=false;
  alumnos.forEach(a=>{
    const claseA=normalizarClase(a.clase);
    const found=storedByNombreClase.find(s=>samePersonName(s.nombre,a.nombre)&&normalizarClase(s.clase)===claseA);
    if(!found)return;
    if(found.bautizado&&!a.bautizado){ a.bautizado=true; changed=true; }
    if(found.sellado&&!a.sellado){ a.sellado=true; changed=true; }
    if(found.nacimiento&&!String(a.nacimiento||"").trim()){ a.nacimiento=found.nacimiento; changed=true; }
    if(found.padre!=null&&String(found.padre).trim()&&!String(a.padre||"").trim()){ a.padre=String(found.padre).trim(); changed=true; }
    if(found.madre!=null&&String(found.madre).trim()&&!String(a.madre||"").trim()){ a.madre=String(found.madre).trim(); changed=true; }
    if(found.telPadre!=null&&String(found.telPadre).trim()&&!String(a.telPadre||"").trim()){ a.telPadre=String(found.telPadre).trim(); changed=true; }
    if(found.telMadre!=null&&String(found.telMadre).trim()&&!String(a.telMadre||"").trim()){ a.telMadre=String(found.telMadre).trim(); changed=true; }
    if(found.familia!=null&&String(found.familia).trim()&&!String(a.familia||"").trim()){ a.familia=String(found.familia).trim(); changed=true; }
    if(found.primerNombre!=null&&String(found.primerNombre).trim()&&!String(a.primerNombre||"").trim()){ a.primerNombre=String(found.primerNombre).trim(); changed=true; }
    if(found.segundoNombre!=null&&String(found.segundoNombre).trim()&&(a.segundoNombre==null||!String(a.segundoNombre).trim())){ a.segundoNombre=String(found.segundoNombre).trim(); changed=true; }
    if(found.primerApellido!=null&&String(found.primerApellido).trim()&&!String(a.primerApellido||"").trim()){ a.primerApellido=String(found.primerApellido).trim(); changed=true; }
    if(found.segundoApellido!=null&&String(found.segundoApellido).trim()&&(a.segundoApellido==null||!String(a.segundoApellido).trim())){ a.segundoApellido=String(found.segundoApellido).trim(); changed=true; }
  });
  return changed;
}

// Reasigna calificaciones cuyos nombres de alumno ya no coinciden exactamente con la lista actual, usando samePersonName+mismo grupo/clase.
// No crea alumnos nuevos: solo apunta las calificaciones al alumno único que ya existe (y normaliza la clase).
function repairCalifsToExistingAlumnos(calificaciones,alumnos){
  if(!Array.isArray(calificaciones)||!Array.isArray(alumnos)||!alumnos.length)return{changed:false,calificaciones:calificaciones||[]};
  let changed=false;
  const nuevos=calificaciones.map(c=>{
    const nombre=(c.alumno||"").trim();
    const claseNorm=normalizarClase(c.clase);
    if(!nombre)return c;
    const candidates=alumnos.filter(a=>samePersonName(a.nombre,nombre)&&normalizarClase(a.clase)===claseNorm);
    if(candidates.length===1){
      const target=candidates[0];
      if(target.nombre!==c.alumno||normalizarClase(target.clase)!==claseNorm){
        changed=true;
        return {...c,alumno:target.nombre,clase:normalizarClase(target.clase)};
      }
    }
    return c;
  });
  return{changed,calificaciones:nuevos};
}

// Deriva la lista de familias desde la lista de alumnos (fuente de verdad). Agrupa por apellidos y padres.
function deriveFamilias(alumnos){
  const norm=(s)=>String(s||"").trim().replace(/\s+/g," ");
  const getApellidos=(a)=>{
    if(a.familia&&norm(a.familia))return norm(a.familia);
    if(a.primerApellido!=null||a.segundoApellido!=null)return norm(buildFamiliaAlumno(a.primerApellido||"",a.segundoApellido||""));
    const p4=parseNombre4(a.nombre||"");return norm(buildFamiliaAlumno(p4.primerApellido,p4.segundoApellido));
  };
  const groups={};
  (alumnos||[]).forEach(a=>{
    const padre=norm(a.padre);
    const madre=norm(a.madre);
    const tienePadreOMadre=!!padre||!!madre;
    const apellidos=getApellidos(a);
    let key;
    if(!tienePadreOMadre)key="__solo__"+a.id;
    else{key=padre+"|"+madre+"|"+apellidos;if(!key||key==="||")key="__solo__"+a.id;}
    if(!groups[key])groups[key]=[];
    groups[key].push(a);
  });
  let numCounter=0;
  const derived=[];
  Object.entries(groups).forEach(([key,members])=>{
    // No conformar familia si no hay al menos un padre o madre; alumno solo no se considera familia
    if(key.startsWith("__solo__"))return;
    numCounter++;
    const first=members[0];
    const familiaLabel=norm(first.familia)||getApellidos(first)||displayNameAlumno(first)||first.nombre||"";
    const familyKey=norm(first.padre)+"|"+norm(first.madre)+"|"+getApellidos(first);
    members.forEach(a=>{
      let edad=null,cumpleanos=null;
      if(a.nacimiento){
        try{
          const d=new Date(a.nacimiento);
          const hoy=new Date();
          edad=String(hoy.getFullYear()-d.getFullYear()-(hoy<new Date(hoy.getFullYear(),d.getMonth(),d.getDate())?1:0));
          cumpleanos=`${String(d.getDate()).padStart(2,"0")}/${String(d.getMonth()+1).padStart(2,"0")}`;
        }catch(e){}
      }
      derived.push({ id: a.id, num: numCounter, familyKey, familia: familiaLabel, padre: a.padre||"", madre: a.madre||"", telPadre: a.telPadre||"", telMadre: a.telMadre||"", alumno: a.nombre, primerNombre: a.primerNombre, segundoNombre: a.segundoNombre, primerApellido: a.primerApellido, segundoApellido: a.segundoApellido, edad, cumpleanos, nacimiento: a.nacimiento||"", clase: normalizarClase(a.clase), bautizado: !!a.bautizado, sellado: !!a.sellado, foto: a.foto||null });
    });
  });
  return derived;
}
